Bash(mkdir -p assets && node -e "
const AdmZip = require\('adm-zip'\);
const fs = require\('fs'\);
const zip = new AdmZip\('מצגת קורטוב תיקונים.pptx'\);

// Extract main images \(jpg/jpeg/png > 10KB\)
const images = zip.getEntries\(\).filter\(e => {
  const name = e.entryName;
  return name.startsWith\('ppt/media/'\) && 
    \(name.endsWith\('.jpg'\) || name.endsWith\('.jpeg'\) || name.endsWith\('.png'\)\) &&
    e.header.size > 10000;
}\);

images.forEach\(e => {
  const filename = e.entryName.split\('/'\).pop\(\);
  fs.writeFileSync\('assets/' + filename, e.getData\(\)\);
  console.log\('Extracted:', filename, e.header.size\);
}\);
")

Bash(node -e "
const AdmZip = require\('adm-zip'\);
const zip = new AdmZip\('מצגת קורטוב תיקונים.pptx'\);

// Check slide relationships to understand which images go where
for \(let i = 1; i <= 11; i++\) {
  const rels = zip.getEntry\('ppt/slides/_rels/slide' + i + '.xml.rels'\);
  if \(rels\) {
    const xml = rels.getData\(\).toString\('utf8'\);
    const imgRefs = [...xml.matchAll\(/Target=\\"\\.\\.\\/media\\/\(image[^\\"]+\)\\"/g\)].map\(m => m[1]\);
    if \(imgRefs.length > 0\) {
      console.log\('Slide ' + i + ':', imgRefs.join\(', '\)\);
    }
  }
}
")

