Bash(node -e "
const fs = require\('fs'\);

// Verify both language objects have same keys
const js = fs.readFileSync\('main.js', 'utf8'\);
const enMatch = js.match\(/en:\\s*\\{\([\\s\\S]+?\)\\n  \\},\\s*\\n\\s*he:/\);
const heMatch = js.match\(/he:\\s*\\{\([\\s\\S]+?\)\\n  \\}\\s*\\n\\};/\);
const enKeys = [...enMatch[1].matchAll\(/^\\s{4}\(\\w+\):/gm\)].map\(m => m[1]\);
const heKeys = [...heMatch[1].matchAll\(/^\\s{4}\(\\w+\):/gm\)].map\(m => m[1]\);

const onlyEn = enKeys.filter\(k => !heKeys.includes\(k\)\);
const onlyHe = heKeys.filter\(k => !enKeys.includes\(k\)\);
console.log\('EN-only keys:', onlyEn.length === 0 ? 'NONE' : onlyEn\);
console.log\('HE-only keys:', onlyHe.length === 0 ? 'NONE' : onlyHe\);
console.log\('EN keys total:', enKeys.length, '| HE keys total:', heKeys.length\);

// Check all referenced assets exist
const html = fs.readFileSync\('index.html', 'utf8'\);
const assets = [...html.matchAll\(/src=\\"assets\\/\([^\\"]+\)\\"/g\)].map\(m => m[1]\);
const missing = assets.filter\(f => !fs.existsSync\('assets/' + f\)\);
console.log\('Missing assets:', missing.length === 0 ? 'NONE' : missing\);
")
